def solve(s: String): String = {
    var result = ""
    for (c <- s) {
        c match {
            case '*' => 
                if (result.nonEmpty) {
                    result = result.dropRight(1)
                }
            case '#' =>
                result = result + result
            case '%' =>
                result = result.reverse
            case _ if c.isLower =>
                result = result + c
            case _ => // do nothing for other characters
        }
    }
    result
}
